[Form]
public class UBSReferencingDocuments extends FormRun
{
    private str storedFileName;

}

    public void init()
    {
        DirPartyTable           dirPartyTable;
        UBSMandatoryDocuments   mandatoryDocuments;
        UBSReferencingDocuments referencingDocuments;
        UBSReferencingRank      referencingRank;
        container               existedDocumentCon;
        
        super();

        if(element.args())
        {
            if(element.args().record() &&
               element.args().record().TableId == tableNum(DirPartyTable))
            {
                dirPartyTable = element.args().record();

                while select UBSDocuments 
                    from referencingDocuments 
                    where referencingDocuments.Party == dirPartyTable.RecId
                {
                    existedDocumentCon += referencingDocuments.UBSDocuments;
                }

                int maxRank = UBSReferencingRank::findByReferencingDocument(dirPartyTable.UBSReferencing).UBSRank;

                ttsbegin;
                while select UBSDocuments from mandatoryDocuments
                    exists join referencingRank
                        where ReferencingRank.UBSReferencing == mandatoryDocuments.UBSReferencing &&
                              ReferencingRank.UBSRank <= maxRank
                {
                        if(!conFind(existedDocumentCon,mandatoryDocuments.UBSDocuments))
                        {
                            referencingDocuments.Party        = dirPartyTable.RecId;
                            referencingDocuments.UBSDocuments = mandatoryDocuments.UBSDocuments;
                            referencingDocuments.insert();
                        }
                }
                ttscommit;
            }
        }
    }

        public void OnUploadCompleted()
        {
            FileUploadTemporaryStorageResult result = this.getFileUploadResult() as FileUploadTemporaryStorageResult;

            super();

            UBSReferencingDocuments referencingDocuments = UBSReferencingDocuments_ds.cursor();

            if(result && result.getUploadStatus())
            {
                str fileName    = result.getFileName();
               
                if(fileName != storedFileName)
                {
                    DocuRef docuRef;

                    using(System.IO.MemoryStream stream = result.openResult() as System.IO.MemoryStream)
                    {
                        docuRef = DocumentManagement::attachFile(
                            tableNum(UBSReferencingDocuments),
                            referencingDocuments.RecId,
                            curext(),
                            DocuType::typeFile(),
                            stream,
                            fileName,
                            null,
                            fileName);
                    }

                    if(docuRef.Name)
                    {
                        ttsbegin;
                        referencingDocuments.selectForUpdate();
                        referencingDocuments.UBSDocumentName = fileName;
                        referencingDocuments.update();
                        ttscommit;
                        storedFileName  = fileName;
                    }

                    Info(strFmt('@UBS:UBSFileUplaoded',fileName));
                    this.fileName("");
                }
                else
                {
                    checkFailed('@UBS:UBSFileUploadCheckFailed');
                }
            }
        }
